SELECT id, template_id, version, field_values_json, submitter_id, tenant_id, submitted_at
FROM form_data
WHERE template_id = #{templateId} AND tenant_id = #{tenantId}

    AND field_values_json LIKE CONCAT('%', #{fieldName}, '%', #{fieldValue}, '%')

ORDER BY submitted_at DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM form_data
WHERE template_id = #{templateId} AND tenant_id = #{tenantId}

    AND field_values_json LIKE CONCAT('%', #{fieldName}, '%', #{fieldValue}, '%')

SELECT id, template_id, version, field_values_json, submitter_id, tenant_id, submitted_at FROM form_data WHERE template_id = #{templateId} AND tenant_id = #{tenantId}
AND field_values_json LIKE CONCAT('%', #{fieldName}, '%', #{fieldValue}, '%')
ORDER BY submitted_at DESC
